105→  const workspace = await surreal.select<{ id: RecordId<"workspace", string> }>(workspaceRecord);
106→  if (!workspace) {
107→    throw new HttpError(404, `workspace not found: ${workspaceId}`);
108→  }
109→  return workspaceRecord;
110→}
111→
112→export async function resolveWorkspaceProjectRecord(
113→  surreal: Surreal,
114→  workspaceRecord: RecordId<"workspace", string>,
115→  projectId: string,
116→): Promise<RecordId<"project", string>> {
117→  const projectRecord = new RecordId("project", projectId);
118→  const project = await surreal.select<{ id: RecordId<"project", string> }>(projectRecord);
119→  if (!project) {
120→    throw new HttpError(404, `project not found: ${projectId}`);
121→  }
122→
123→  const [edgeRows] = await surreal
124→    .query<[HasProjectRow[]]>(
125→      "SELECT id FROM has_project WHERE `in` = $workspace AND out = $project LIMIT 1;",
126→      {
127→        workspace: workspaceRecord,
128→        project: projectRecord,
129→      },
130→    )
131→    .collect<[HasProjectRow[]]>();
132→
133→  if (edgeRows.length === 0) {
134→    throw new HttpError(400, "project is not linked to workspace");
135→  }
136→
137→  return projectRecord;
138→}
139→
140→export async function loadWorkspaceProjects(
141→  surreal: Surreal,
142→  workspaceRecord: RecordId<"workspace", string>,
143→): Promise<ProjectScopeRow[]> {
144→  const [rows] = await surreal
145→    .query<[ProjectScopeRow[]]>(
146→      "SELECT id, name FROM project WHERE id IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace);",
147→      {
148→        workspace: workspaceRecord,
149→      },
150→    )
151→    .collect<[ProjectScopeRow[]]>();
152→
153→  return rows;
154→}
155→
156→export function resolveEntityProject(
157→  entityText: string,
158→  promptText: string,
159→  projects: ProjectScopeRow[],
160→): RecordId<"project", string> | undefined {
161→  if (projects.length === 0) {
162→    return undefined;
163→  }
164→
165→  if (projects.length === 1) {
166→    return projects[0].id;
167→  }
168→
169→  const haystack = `${promptText}\n${entityText}`;
170→  const matchingProjects = projects.filter((project) => {
171→    const escaped = project.name.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
172→    return new RegExp(`\\b${escaped}\\b`, "i").test(haystack);
173→  });
174→
175→  if (matchingProjects.length !== 1) {
176→    return undefined;
177→  }
178→
179→  return matchingProjects[0].id;
180→}
