 16→import type { ChatToolDeps } from "./types";
 17→
 18→export function createCreateWorkItemTool(deps: ChatToolDeps) {
 19→  return tool({
 20→    description:
 21→      "Create a task, feature, or project directly in the knowledge graph. Use when the user explicitly requests creation (\"add a task for X\") or during onboarding entity seeding. For uncertain/brainstormed items, prefer suggest_work_items instead.",
 22→    inputSchema: z.object({
 23→      kind: z.enum(["task", "feature", "project"]).describe(
 24→        "project: named product area or workstream (MUST create before features/tasks can belong to it). feature: capability within an existing project. task: concrete executable work with action verb. If no projects exist yet, create a project first.",
 25→      ),
 26→      title: z.string().min(1).describe("Concise entity title"),
 27→      rationale: z.string().min(1).describe("Why this entity is needed — seeds the description"),
 28→      category: z.enum(ENTITY_CATEGORIES).optional().describe("Category classification"),
 29→      priority: z.enum(ENTITY_PRIORITIES).optional().describe("critical: blocking/urgent. high: important, needs attention soon. medium: normal priority. low: nice-to-have, deferred."),
 30→      project: z.string().optional().describe("Project name to scope the entity under"),
 31→    }),
 32→    execute: async (input, options) => {
 33→      const { context } = await requireAuthorizedContext(options, "create_task", deps);
 34→      const now = new Date();
 35→
 36→      const embedding = await createEmbeddingVector(
 37→        deps.embeddingModel,
 38→        input.title,
 39→        deps.embeddingDimension,
 40→      );
 41→
 42→      const entityId = randomUUID();
 43→
 44→      // Hard guard: never create a project with the same name as the workspace
 45→      if (input.kind === "project") {
 46→        const [ws] = await deps.surreal.query<[{ name: string } | undefined]>(
 47→          "SELECT name FROM ONLY $ws;",
 48→          { ws: context.workspaceRecord },
 49→        );
 50→        if (ws && input.title.toLowerCase().trim() === ws.name.toLowerCase().trim()) {
 51→          return {
 52→            error: `"${input.title}" is the workspace name, not a project. Create the user's described items (e.g. Dashboard, Inventory) as projects instead.`,
 53→          };
 54→        }
 55→
 56→        const projectRecord = await createProjectRecord({
 57→          surreal: deps.surreal,
 58→          name: input.title,
 59→          status: "active",
 60→          now,
 61→          workspaceRecord: context.workspaceRecord,
 62→          sourceMessageRecord: context.currentMessageRecord,
 63→        });
 64→
 65→        if (embedding) {
 66→          await deps.surreal.update(projectRecord).merge({ embedding });
 67→        }
 68→
 69→        void seedDescriptionEntry({
 70→          surreal: deps.surreal,
 71→          targetRecord: projectRecord,
 72→          text: input.rationale,
 73→        }).catch(() => undefined);
 74→
 75→        await createExtractionProvenanceEdge({
 76→          surreal: deps.surreal,
 77→          sourceRecord: context.currentMessageRecord,
 78→          targetRecord: projectRecord,
 79→          now,
 80→          confidence: 0.95,
 81→          model: deps.extractionModelId,
 82→          fromText: input.title,
 83→          evidence: context.latestUserText,
 84→          evidenceSourceRecord: context.currentMessageRecord,
 85→        });
 86→
 87→        return {
 88→          entity_id: `project:${projectRecord.id as string}`,
 89→          kind: "project" as const,
 90→          title: input.title,
 91→        };
 92→      }
 93→
 94→      if (input.kind === "task") {
 95→        const taskRecord = new RecordId("task", entityId);
 96→        await deps.surreal.create(taskRecord).content({
 97→          title: input.title,
 98→          status: "open",
 99→          workspace: context.workspaceRecord,
100→          ...(input.category ? { category: input.category } : {}),
101→          ...(input.priority ? { priority: input.priority } : {}),
102→          ...(embedding ? { embedding } : {}),
103→          created_at: now,
104→          updated_at: now,
105→        });
106→
107→        if (input.project) {
108→          try {
109→            const projectRecord = await resolveWorkspaceProjectRecord({
110→              surreal: deps.surreal,
111→              workspaceRecord: context.workspaceRecord,
112→              projectInput: input.project,
113→            });
114→            await deps.surreal
115→              .relate(taskRecord, new RecordId("belongs_to", randomUUID()), projectRecord, {
116→                added_at: now,
117→              })
118→              .output("after");
119→          } catch {
120→            // project resolution is best-effort
121→          }
122→        }
123→
124→        void seedDescriptionEntry({
125→          surreal: deps.surreal,
126→          targetRecord: taskRecord,
127→          text: input.rationale,
128→        }).catch(() => undefined);
129→
130→        await createExtractionProvenanceEdge({
131→          surreal: deps.surreal,
132→          sourceRecord: context.currentMessageRecord,
133→          targetRecord: taskRecord,
134→          now,
135→          confidence: 0.95,
136→          model: deps.extractionModelId,
137→          fromText: input.title,
138→          evidence: context.latestUserText,
139→          evidenceSourceRecord: context.currentMessageRecord,
140→        });
141→
142→        return {
143→          entity_id: `task:${entityId}`,
144→          kind: "task" as const,
145→          title: input.title,
146→        };
147→      }
148→
149→      // feature
150→      const featureRecord = new RecordId("feature", entityId);
151→      await deps.surreal.create(featureRecord).content({
152→        name: input.title,
153→        status: "active",
154→        ...(input.category ? { category: input.category } : {}),
155→        ...(embedding ? { embedding } : {}),
156→        created_at: now,
157→        updated_at: now,
158→      });
159→
160→      if (input.project) {
161→        try {
162→          const projectRecord = await resolveWorkspaceProjectRecord({
163→            surreal: deps.surreal,
164→            workspaceRecord: context.workspaceRecord,
165→            projectInput: input.project,
166→          });
167→          await ensureProjectFeatureEdge(deps.surreal, projectRecord, featureRecord, now);
168→
169→          void fireDescriptionUpdates({
170→            surreal: deps.surreal,
171→            extractionModel: deps.extractionModel,
172→            trigger: {
173→              kind: "feature_created",
174→              entity: featureRecord,
175→              summary: `Feature added: ${input.title}`,
176→            },
177→          }).catch(() => undefined);
178→        } catch {
179→          // project resolution is best-effort
180→        }
181→      }
182→
183→      void seedDescriptionEntry({
184→        surreal: deps.surreal,
185→        targetRecord: featureRecord,
186→        text: input.rationale,
187→      }).catch(() => undefined);
188→
189→      await createExtractionProvenanceEdge({
190→        surreal: deps.surreal,
191→        sourceRecord: context.currentMessageRecord,
192→        targetRecord: featureRecord,
193→        now,
194→        confidence: 0.95,
195→        model: deps.extractionModelId,
196→        fromText: input.title,
197→        evidence: context.latestUserText,
198→        evidenceSourceRecord: context.currentMessageRecord,
199→      });
200→
201→      return {
202→        entity_id: `feature:${entityId}`,
203→        kind: "feature" as const,
204→        title: input.title,
205→      };
206→    },
207→  });
208→}
