473→DEFINE FUNCTION fn::entity_search_workspace($q: string, $limit: int, $workspace: record<workspace>) {
474→  LET $query = string::lowercase(string::trim($q));
475→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
476→
477→  LET $task_rows = SELECT
478→    id,
479→    "task" AS kind,
480→    title AS text,
481→    extraction_confidence AS confidence,
482→    source_message AS sourceMessage,
483→    priority,
484→    created_at
485→  FROM task
486→  WHERE workspace = $workspace
487→    AND extraction_confidence != NONE
488→    AND string::contains(string::lowercase(title), $query)
489→  ORDER BY created_at DESC
490→  LIMIT $safe_limit;
491→
492→  LET $decision_rows = SELECT
493→    id,
494→    "decision" AS kind,
495→    summary AS text,
496→    extraction_confidence AS confidence,
497→    source_message AS sourceMessage,
498→    priority,
499→    created_at
500→  FROM decision
501→  WHERE workspace = $workspace
502→    AND extraction_confidence != NONE
503→    AND string::contains(string::lowercase(summary), $query)
504→  ORDER BY created_at DESC
505→  LIMIT $safe_limit;
506→
507→  LET $question_rows = SELECT
508→    id,
509→    "question" AS kind,
510→    text AS text,
511→    extraction_confidence AS confidence,
512→    source_message AS sourceMessage,
513→    priority,
514→    created_at
515→  FROM question
516→  WHERE workspace = $workspace
517→    AND extraction_confidence != NONE
518→    AND string::contains(string::lowercase(text), $query)
519→  ORDER BY created_at DESC
520→  LIMIT $safe_limit;
521→
522→  RETURN array::flatten([$task_rows, $decision_rows, $question_rows]);
523→};
