302→export async function listConversationEntities(input: {
303→  surreal: Surreal;
304→  conversationRecord: RecordId<"conversation", string>;
305→  workspaceRecord: RecordId<"workspace", string>;
306→  limit: number;
307→  inheritedEntityIds?: RecordId[];
308→}): Promise<ConversationEntity[]> {
309→  const [rows] = await input.surreal
310→    .query<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>(
311→      [
312→        "SELECT `in`, out, confidence, extracted_at",
313→        "FROM extraction_relation",
314→        "WHERE `in` IN (SELECT VALUE id FROM message WHERE conversation = $conversation)",
315→        "ORDER BY extracted_at DESC",
316→        "LIMIT $limit;",
317→      ].join(" "),
