376→          "ORDER BY extracted_at DESC",
377→          "LIMIT $limit;",
378→        ].join(" "),
379→        { entityIds: input.inheritedEntityIds, limit: input.limit },
380→      )
381→      .collect<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>();
382→
383→    for (const row of inheritedRows) {
384→      const table = row.out.table.name as GraphEntityTable;
385→      if (
386→        table !== "workspace" &&
387→        table !== "project" &&
388→        table !== "person" &&
389→        table !== "feature" &&
390→        table !== "task" &&
391→        table !== "decision" &&
392→        table !== "question" &&
393→        table !== "suggestion"
394→      ) {
395→        continue;
396→      }
397→
398→      const entityKey = `${table}:${toRecordIdString(row.out)}`;
399→      if (seen.has(entityKey)) continue;
400→
401→      const name = await readEntityName(input.surreal, row.out);
402→      if (!name) continue;
403→
404→      items.push({
405→        id: toRecordIdString(row.out),
406→        kind: table,
407→        name,
408→        confidence: row.confidence,
409→        sourceMessageId: toRecordIdString(row.in),
410→      });
411→      seen.add(entityKey);
412→    }
413→  }
