+    const result = await tool.execute!(
+      { entity_ids: ["decision:fake-id"], target_project: "Some Project" },
+      makeOptions(),
+    );
+
+    expect(result.failed).toHaveLength(1);
+    expect(result.failed[0].reason).toContain("must be one of");
+  });
+});

